{
  "schema_version": "v1",
  "plan_id": "review-compression-schema-and-engine",
  "plan_revision": 2,
  "title": "Review Compression System",
  "boundary": "review-compression-schema-and-engine",
  "consumer_purpose": "Produce a weighted review manifest per campaign showing developers only what they actually need to review, not every changed line",
  "prerequisite_conditions": [
    "PRE-001: Create 3 governance schemas mandated by AGENTS.md — builder_publication_record.v1, verification_record.v1, prepublication_review_cycle.v1. These are shared infrastructure with IN-003 Evidence-Gated Push."
  ],
  "subagent_findings_incorporated": {
    "impact_assessor": "docs/json/opencode/impact/in-002-review-compression-downstream-impact.v1.json",
    "critic": "docs/json/opencode/criticism/in-002-review-compression-critique.v1.json",
    "key_insights": [
      "builder_publication_record must reconcile v1 (22 fields) and v2 (14 fields) via oneOf or version discrimination",
      "prepublication_review_cycle schema must align with 3 existing tools (admitted/blocked/inconclusive) that write ad-hoc JSON with different field names (admitted_at vs issued_at, notes vs reason vs blocker_description)",
      "BinderService.getBinders() returns [] — persistence is stubbed. Engine must not depend on binder data",
      "Cross-lane seam with IN-003: items 2, 3, 4 are shared schema dependencies. Coordinate before advancing",
      "Plan `files` field is a convergence precondition — without it, claim-to-file matching is unreliable",
      "Error handling strategy and degradation tiers are missing from Phase 1 design",
      "Weight rubric needs audit trail: versioned rules, per-entry rationale arrays",
      "5 incompatible validation schemas need a normalizer module, not ad-hoc handling"
    ]
  },
  "design_decisions": [
    {
      "id": "DD-001",
      "title": "New manifest schema, not an extension of existing ones",
      "rationale": "The review manifest aggregates across 4+ data sources — no existing schema fits this role.",
      "decision": "Create docs/schemas/rig.relay.review_manifest.v1.schema.json as standalone schema"
    },
    {
      "id": "DD-002",
      "title": "Plan must gain `files` field for reliable convergence",
      "rationale": "critic found <30% of claim_atoms contain parseable file references. Without structured file paths, the comparison engine cannot converge on correct matching. Adding a `files` array to the plan schema is a precondition.",
      "decision": "Phase 0: Add optional `files` field (array of globs) to plan artifacts. Comparison engine matches against explicit files[] first. Unverifiable claims surface as 'unverifiable' not silently omitted."
    },
    {
      "id": "DD-003",
      "title": "ValidationRun normalizer as separate module",
      "rationale": "5 incompatible validation schemas with different verdict vocabularies. A normalizer abstracts over all formats and produces ValidationRun[] — the compressor consumes validated runs, not raw files.",
      "decision": "Create packages/opencode/src/review/validation.ts as a separate, testable module for reading and normalizing all 5+ validation formats into ValidationRun[]"
    },
    {
      "id": "DD-004",
      "title": "Error handling and data quality tracking are first-class manifest sections",
      "rationale": "Missing or corrupt data sources must produce degraded manifests with clear labels, not silent omissions. Every manifest section is one of available/missing/error.",
      "decision": "Add `data_quality` section to review_manifest schema tracking per-source: availability, parse status, recovery action"
    },
    {
      "id": "DD-005",
      "title": "Weight rubric is versioned with per-entry audit trail",
      "rationale": "Opaque weight labels make misclassification undiagnosable. Each entry must record which rule matched and why.",
      "decision": "Weight entry: { file, weight, rationale: string[], matching_rules: string[] }. Rubric_version stored in manifest. Override mechanism remains."
    },
    {
      "id": "DD-006",
      "title": "Three-track phasing: prerequisites, core manifest, weight rubric enhancement",
      "rationale": "Critic found ~80% scope inflation from governance policy debt. Splitting into tracks isolates prerequisites from core deliverables.",
      "decision": "Track A (P0 prerequisites): governance schemas + plan files field + plan schema validation + fix session-diff placeholder. Track B (P0 core): review_manifest schema + validation normalizer + exact-match comparison engine + manifest generator. Track C (P1): weight rubric + integration."
    },
    {
      "id": "DD-007",
      "title": "Manifest generated per-campaign, not per-session",
      "rationale": "A lane goes through plan → execution → validation → stress → publication lifecycle. Per-session manifests would miss plan and cross-session context.",
      "decision": "Manifest is generated at publication time, keyed by publication record's boundary identifier"
    }
  ],
  "deliverables": {
    "track_a_prerequisites": {
      "description": "Track A (P0): Governance schema creation and plan schema hardening — shared infrastructure with IN-003",
      "items": [
        {
          "id": "A-001",
          "title": "rig.relay.builder_publication_record.v1 schema",
          "file": "docs/schemas/rig.relay.builder_publication_record.v1.schema.json",
          "design_constraints": [
            "Must use oneOf to reconcile v1 (22 fields with inline prepublication_review_cycle) and v2 (14 fields with cleaner structure)",
            "Must accommodate publications.v1.jsonl ledger format (checkpoint_sha, boundary, changed_files, deferred_seams, verdict, publisher_session)",
            "Source examples: docs/json/opencode/publication_record.v1.json, docs/json/opencode/publication_record.v2.json, docs/json/opencode/publications/publications.v1.jsonl"
          ]
        },
        {
          "id": "A-002",
          "title": "rig.relay.verification_record.v1 schema",
          "file": "docs/schemas/rig.relay.verification_record.v1.schema.json",
          "design_constraints": [
            "Forward-looking design — no existing verification artifacts to reverse-engineer",
            "Must align with campaign/binder.ts types (ValidationResult has kind/passed/reason/evidence)",
            "Must NOT conflict with existing approval field semantics in docs/json/opencode/approvals/"
          ]
        },
        {
          "id": "A-003",
          "title": "rig.relay.prepublication_review_cycle.v1 schema",
          "file": "docs/schemas/rig.relay.prepublication_review_cycle.v1.schema.json",
          "design_constraints": [
            "Must reconcile inline formats from publication_record.v1.json and v2.json",
            "CRITICAL: Must align with 3 existing tools that write ad-hoc JSON with different field names — prepublication-admitted.ts (uses admitted_at), prepublication-blocked.ts (uses issued_at, blocker_description, repair_path), prepublication-inconclusive.ts (uses reason)",
            "Tools MAY need to be updated if schema introduces structural differences (e.g., rounds[] array vs flat review_round field)"
          ],
          "production_risk": "HIGH — three prepublication tools write string-literals for field names with no TypeScript boundary. Schema field name mismatches only surface at runtime."
        },
        {
          "id": "A-004",
          "title": "Add `files` field to plan artifacts",
          "file": "packages/opencode/src/tool/propose-plan.ts",
          "design_constraints": [
            "Add optional `files` field (Schema.Array(Schema.String)) to plan Parameters schema",
            "Backward compatible — existing plans without `files` field still work (comparison engine falls back to content scan)",
            "Format: array of glob patterns (e.g., ['packages/opencode/src/tool/cache.ts', 'packages/opencode/src/review/**'])",
            "Critic finding PRE-002: without this, claim-to-file convergence is impossible"
          ]
        },
        {
          "id": "A-005",
          "title": "Fix session-diff.ts placeholder status",
          "file": "packages/opencode/src/tool/session-diff.ts",
          "design_constraints": [
            "Critic finding PRE-003: a placeholder tool cannot be a production dependency for the comparison engine",
            "Must ensure the tool properly resolves session paths and returns structured diff data"
          ]
        }
      ]
    },
    "track_b_manifest_core": {
      "description": "Track B (P0): Review manifest schema, validation normalizer, comparison engine, and manifest generator",
      "items": [
        {
          "id": "B-001",
          "title": "rig.relay.review_manifest.v1 schema",
          "file": "docs/schemas/rig.relay.review_manifest.v1.schema.json",
          "required_sections": [
            "manifest_id, lane_id, boundary, generated_at — identity",
            "plan_summary: plan_id, revision, claim_atoms, boundary, planned_files — what was planned",
            "diff_summary: total_files, total_additions, total_deletions, per_file breakdown — what actually changed",
            "plan_vs_diff_deviation: files_in_scope (plan ∩ actual), files_outside_scope (actual \\ plan), unmatched_claim_atoms, unverifiable_claims — drift detection with confidence levels",
            "validation_summary: commands_run, test_deltas, pass_fail_counts, stress_results — what was validated",
            "review_weight_map: per-file weight classification with rubric_element rationale — what to focus on",
            "residual_risks: surviving_weaknesses, deferred_seams, repair_debt — what remains",
            "data_quality: per-source status tracking — every section must be one of available | missing | error",
            "provenance: data_sources_used, generator_tool, generator_session, generated_at, trust_score — audit trail"
          ],
          "critic_section": {
            "data_quality": "Per-source availability status (available/missing/error) with parse status and recovery action",
            "claim_verifiability": "Every claim classified as exact_match | pattern_match | unverifiable | mismatch",
            "trust_score": "Prepublication provenance signal — counters SG-006 fabrication risk",
            "rubric_version": "Stored in manifest for weight regression auditing"
          }
        },
        {
          "id": "B-002",
          "title": "ValidationRun normalizer module",
          "file": "packages/opencode/src/review/validation.ts",
          "design": {
            "purpose": "Abstract over 5+ incompatible validation schema formats (validation_report.v1, qa.validation.v1, validation_artifact.v1, qa.verification.v1, stress_report.v1) and produce a uniform ValidationRun[]",
            "interface": "normalizeValidationRun(input: UnknownRecord): Effect.Effect<ValidationRun>",
            "formats_supported": [
              "Execution wave records (snapshot-based)",
              "Stress wave records (attack/finding/verdict)",
              "QA observations (plan_id, boundary, verdict)",
              "Validation artifacts (criteria/findings/verdict)",
              "Custom stress reports (red-team findings)"
            ]
          }
        },
        {
          "id": "B-003",
          "title": "Comparison engine",
          "file": "packages/opencode/src/review/comparison.ts",
          "design": {
            "input": "Plan artifact + Snapshot.FileDiff[] + Project files config",
            "output": "DeviationReport with confidence scoring",
            "algorithm": [
              "Step 1: Extract planned files from plan.`files` field (if present) → exact glob matching. If no `files` field, scan claim_atoms for file path patterns (regex heuristic) as FALLBACK with 'unverifiable' confidence",
              "Step 2: Extract actual files from FileDiff[].file (union of added/deleted/modified)",
              "Step 3: in_scope = planned_files ∩ actual_files (with glob resolution)",
              "Step 4: out_of_scope = actual_files \\ planned_files",
              "Step 5: unverifiable_claims = claim_atoms with no parseable file reference",
              "Step 6: unmatched_claims = claim_atoms whose files don't appear in actual_files"
            ],
            "confidence_scoring": {
              "exact_match": "Glob pattern in files[] matched actual file path — highest confidence",
              "pattern_match": "File path extracted from claim_atom prose matched actual file — medium confidence",
              "unverifiable": "Claim has no parseable file reference — marked for human review",
              "mismatch": "Claim has file reference but it doesn't match any actual diff — deviation"
            }
          }
        },
        {
          "id": "B-004",
          "title": "Manifest generator service",
          "file": "packages/opencode/src/review/manifest.ts",
          "design": {
            "interface": "GenerateManifestInput → Effect.Effect<ReviewManifest>",
            "error_handling": "Each data source loaded independently with try/catch. Failed source → section.data_quality = 'error' with error message. Missing source → section.data_quality = 'missing'. All available sources → section.data_quality = 'available'.",
            "graceful_degradation": [
              "No plan artifact found → plan_summary omitted with data_quality='missing', note 'no plan artifact'",
              "No diffs available → diff_summary says 'no diff' instead of crashing",
              "Corrupt validation JSON → generic parse error with file path context",
              "Publication record not found → manifest generated with plan+diff+validation only"
            ]
          }
        }
      ]
    },
    "track_c_weight_rubric": {
      "description": "Track C (P1): Weight rubric as enhancement to manifest core — delivered after Track B stabilizes",
      "items": [
        {
          "id": "C-001",
          "title": "Weight rubric rules engine",
          "file": "packages/opencode/src/review/weight.ts",
          "design": {
            "rubric_rules": [
              {"weight": "hidden", "patterns": ["**/pnpm-lock.*", "**/bun.lock*", "**/*.generated.*", "**/__generated__/**"]},
              {"weight": "low", "patterns": ["**/i18n/**", "**/*.md", "**/CHANGELOG.*"], "changeType_allow": ["modified"]},
              {"weight": "medium", "patterns": ["**/*.d.ts", "**/*.css", "**/i18n/*.ts", "**/*.test.*", "**/*.spec.*"], "conditions": {}},
              {"weight": "high", "patterns": ["**/ipc.*", "**/preload/**", "**/security/**", "**/auth/**", "**/permission*", "**/*.schema.json", "**/govern*/**"]},
              {"weight": "critical", "conditions": ["patch_contains_security_keywords", "file_changed_after_validation", "diff_not_in_plan"]}
            ],
            "audit_trail": "Each weight entry records { file, weight, rationale: [which_rule_matched, why], matching_rules: [rule_ids] }. Rubric_version stored in manifest.",
            "override_mechanism": "Reviewer can add `exceptions` array to manifest with { file, overrideWeight, rationale }",
            "default_weight": "medium with rationale 'unclassified'"
          }
        }
      ]
    }
  },
  "work_breakdown": [
    {
      "id": "A-001",
      "track": "A",
      "priority": "P0",
      "title": "Create builder_publication_record.v1 schema",
      "files": [{"file": "docs/schemas/rig.relay.builder_publication_record.v1.schema.json", "action": "create"}],
      "deps": [],
      "coordinated_with": "IN-003 (shared schema dependency — coordinate field design before creating)"
    },
    {
      "id": "A-002",
      "track": "A",
      "priority": "P0",
      "title": "Create verification_record.v1 schema",
      "files": [{"file": "docs/schemas/rig.relay.verification_record.v1.schema.json", "action": "create"}],
      "deps": [],
      "coordinated_with": "IN-003 (shared schema dependency)"
    },
    {
      "id": "A-003",
      "track": "A",
      "priority": "P0",
      "title": "Create prepublication_review_cycle.v1 schema",
      "files": [{"file": "docs/schemas/rig.relay.prepublication_review_cycle.v1.schema.json", "action": "create"}],
      "deps": [],
      "coordinated_with": "IN-003 (shared schema dependency). Post-creation: validate against 3 prepublication tool outputs, update tools if schema structural differences exist"
    },
    {
      "id": "A-004",
      "track": "A",
      "priority": "P0",
      "title": "Add `files` field to plan Parameters schema",
      "files": [{"file": "packages/opencode/src/tool/propose-plan.ts", "action": "modify"}],
      "deps": []
    },
    {
      "id": "A-005",
      "track": "A",
      "priority": "P0",
      "title": "Fix session-diff.ts placeholder status",
      "files": [{"file": "packages/opencode/src/tool/session-diff.ts", "action": "modify"}],
      "deps": []
    },
    {
      "id": "A-006",
      "track": "A",
      "priority": "P0",
      "title": "Validate all 3 governance schemas",
      "deps": ["A-001", "A-002", "A-003"],
      "validation": "scripts/rig_relay_validate_schemas.py && tests/coordination/test_schema_validation.py"
    },
    {
      "id": "B-001",
      "track": "B",
      "priority": "P0",
      "title": "Create review_manifest.v1 schema",
      "files": [{"file": "docs/schemas/rig.relay.review_manifest.v1.schema.json", "action": "create"}],
      "deps": ["A-001", "A-002", "A-003"],
      "features": ["data_quality section", "claim_verifiability classification", "per-section availability tiers", "trust_score", "rubric_version"]
    },
    {
      "id": "B-002",
      "track": "B",
      "priority": "P0",
      "title": "Build validation normalizer module",
      "files": [{"file": "packages/opencode/src/review/validation.ts", "action": "create"}],
      "deps": ["A-006"]
    },
    {
      "id": "B-003",
      "track": "B",
      "priority": "P0",
      "title": "Build comparison engine",
      "files": [
        {"file": "packages/opencode/src/review/comparison.ts", "action": "create"},
        {"file": "packages/opencode/src/review/types.ts", "action": "create"},
        {"file": "packages/opencode/src/review/index.ts", "action": "create"}
      ],
      "deps": ["B-001", "A-004", "A-005"],
      "critic_addressed": "Claim verifiability classification (exact_match/pattern_match/unverifiable/mismatch) prevents silent convergence failure"
    },
    {
      "id": "B-004",
      "track": "B",
      "priority": "P0",
      "title": "Build manifest generator",
      "files": [{"file": "packages/opencode/src/review/manifest.ts", "action": "create"}],
      "deps": ["B-002", "B-003"],
      "critic_addressed": "Graceful degradation — each source loaded independently; failed source → section.data_quality = 'error'"
    },
    {
      "id": "B-005",
      "track": "B",
      "priority": "P0",
      "title": "Create review_manifest tool",
      "files": [
        {"file": "packages/opencode/src/tool/review-manifest.ts", "action": "create"},
        {"file": "packages/opencode/src/tool/registry.ts", "action": "modify"},
        {"file": "packages/opencode/src/campaign/role-contracts.ts", "action": "modify"}
      ],
      "deps": ["B-004"]
    },
    {
      "id": "C-001",
      "track": "C",
      "priority": "P1",
      "title": "Build weight rubric rules engine",
      "files": [{"file": "packages/opencode/src/review/weight.ts", "action": "create"}],
      "deps": ["B-004"]
    }
  ],
  "risks": [
    {
      "id": "RISK-001",
      "severity": "high",
      "description": "claim_atoms without `files` field — comparison engine falls back to unreliable prose matching",
      "mitigation": "A-004 adds `files` field to plan schema. Engine uses three-tier: exact glob → atom keyword → content scan. Unverifiable claims flagged as such, not silently omitted"
    },
    {
      "id": "RISK-002",
      "severity": "high",
      "description": "prepublication_review_cycle schema must align with 3 existing tools writing ad-hoc JSON with incompatible field names",
      "mitigation": "Schema design accommodates all three variants via optional fields. Tools evaluated for update necessity post-schema"
    },
    {
      "id": "RISK-003",
      "severity": "medium",
      "description": "prepublication verdict fabrication (SG-006) — manifest surfaces fabricated entries as genuine",
      "mitigation": "Provenance block + trust_score counters this. Every manifest entry records its generator_tool, generator_session, timestamp"
    },
    {
      "id": "RISK-004",
      "severity": "medium",
      "description": "BinderService persistence is stubbed — engine must not depend on it",
      "mitigation": "Engine reads directly from filesystem (plan artifacts, validation logs), not from BinderService"
    },
    {
      "id": "RISK-005",
      "severity": "medium",
      "description": "Cross-lane seam with IN-003: 3 shared governance schemas may diverge in field design",
      "mitigation": "Coordinate schema field design with IN-003 before creation. Agree on shared $id convention and field semantics"
    },
    {
      "id": "RISK-006",
      "severity": "low",
      "description": "Weight rubric entries opaque — misclassification undiagnosable",
      "mitigation": "C-001 requires per-entry rationale[] + matching_rules[] arrays. Rubric_version in manifest"
    },
    {
      "id": "RISK-007",
      "severity": "low",
      "description": "Artifact fragmentation — data across 5+ directories",
      "mitigation": "Graceful degradation. Manifest generator loads each source independently"
    }
  ],
  "validation_strategy": {
    "schema_validation": "scripts/rig_relay_validate_schemas.py for all 4 schemas",
    "prepublication_tool_alignment": "Post A-003: validate prepublication_{admitted,blocked,inconclusive}.v1.json against new schema",
    "publication_record_alignment": "Post A-001: validate publication_record.v1.json, v2.json, and publications.v1.jsonl entries against new schema",
    "plan_schema_backward_compat": "Post A-004: existing plans without `files` field must still load and validate",
    "comparison_engine": "Unit tests with synthetic FileDiff[] and plan artifacts covering: exact glob match, pattern match, unverifiable claim, mismatch",
    "weight_rubric": "Table-driven tests: input file path → expected weight. Edge cases: generated files, security paths, IPC paths, test files, unknown extensions",
    "integration": "End-to-end test: read real plan → load validation records → generate manifest → validate against review_manifest.v1 schema",
    "type_safety": "cd packages/opencode && bun typecheck after each Track B and C change",
    "test_suite": "cd packages/opencode && bun test after each phase"
  },
  "completion_criteria": {
    "track_a": "All 3 governance schemas pass schema validation and align with existing tool outputs. Plan `files` field is optional and backward-compatible. session-diff.ts is no longer a placeholder.",
    "track_b": "review_manifest schema validates. Comparison engine returns correct DeviationReport with confidence scores. Manifest generator produces valid output for a real lane with graceful degradation. Tool registered and accessible to historian agent.",
    "track_c": "Weight rubric returns correct weights for known test fixtures. Per-entry audit trail present in manifest output."
  }
}
